text:
In fact, I like this patch better.
It installs a sample configuration file as well (snarfed from the distfile,
but edited to use example.net and example.com and RFC1918 addresses).


diff -rPU3 net/isc-dhcp2.old/Makefile net/isc-dhcp2/Makefile
--- net/isc-dhcp2.old/Makefile	Sun Nov 25 16:26:17 2001
+++ net/isc-dhcp2/Makefile	Sun Nov 25 16:52:14 2001
@@ -7,6 +7,7 @@

 PORTNAME=	isc-dhcp
 PORTVERSION=	2.0.5
+PORTREVISION=	1
 CATEGORIES=	net
 MASTER_SITES=	ftp://ftp.isc.org/isc/dhcp/ \
 		ftp://ftp.isc.org/isc/dhcp/dhcp-2.0-history/
@@ -34,5 +35,8 @@
 .endfor
 	${INSTALL_SCRIPT} ${FILESDIR}/${STARTUP_SCRIPT} \
 			${PREFIX}/etc/rc.d/${STARTUP_SCRIPT}
+
+	${INSTALL_SCRIPT} ${FILESDIR}/dhcpd.conf.sample \
+			${PREFIX}/etc/dhcpd.conf.sample

 .include <bsd.port.mk>
diff -rPU3 net/isc-dhcp2.old/files/dhcpd.conf.sample net/isc-dhcp2/files/dhcpd.conf.sample
--- net/isc-dhcp2.old/files/dhcpd.conf.sample	Thu Jan  1 01:00:00 1970
+++ net/isc-dhcp2/files/dhcpd.conf.sample	Sun Nov 25 16:50:56 2001
@@ -0,0 +1,90 @@
+# dhcpd.conf
+#
+# Sample configuration file for ISC dhcpd
+#
+
+# option definitions common to all supported networks...
+option domain-name "example.com";
+option domain-name-servers ns1.example.com;
+
+option subnet-mask 255.255.255.224;
+default-lease-time 600;
+max-lease-time 7200;
+
+subnet 10.11.12.0 netmask 255.255.255.224 {
+  range 10.11.12.10 10.11.12.20;
+  option broadcast-address 10.11.12.31;
+  option routers gw1.example.com;
+}
+
+# The other subnet that shares this physical network
+subnet 10.11.12.32 netmask 255.255.255.224 {
+  range dynamic-bootp 10.11.12.40 10.11.12.50;
+  option broadcast-address 10.11.12.63;
+  option routers gw2.example.com;
+}
+
+subnet 172.25.5.0 netmask 255.255.255.224 {
+  range 172.25.5.26 172.25.5.30;
+  option name-servers ns1.example.net, ns2.example.net;
+  option domain-name "example.net";
+  option routers 172.25.5.1;
+  option subnet-mask 255.255.255.224;
+  option broadcast-address 172.25.5.31;
+  default-lease-time 600;
+  max-lease-time 7200;
+}
+
+# Hosts which require special configuration options can be listed in
+# host statements.   If no address is specified, the address will be
+# allocated dynamically (if possible), but the host-specific information
+# will still come from the host declaration.
+
+host passacaglia {
+  hardware ethernet 0:0:c0:5d:bd:95;
+  filename "vmunix.passacaglia";
+  server-name "bootp.example.com";
+}
+
+# Fixed IP addresses can also be specified for hosts.   These addresses
+# should not also be listed as being available for dynamic assignment.
+# Hosts for which fixed IP addresses have been specified can boot using
+# BOOTP or DHCP.   Hosts for which no fixed address is specified can only
+# be booted with DHCP, unless there is an address range on the subnet
+# to which a BOOTP client is connected which has the dynamic-bootp flag
+# set.
+host fantasia {
+  hardware ethernet 08:00:07:26:c0:a5;
+  fixed-address fantasia.example.com;
+}
+
+# If a DHCP or BOOTP client is mobile and might be connected to a variety
+# of networks, more than one fixed address for that host can be specified.
+# Hosts can have fixed addresses on some networks, but receive dynamically
+# allocated address on other subnets; in order to support this, a host
+# declaration for that client must be given which does not have a fixed
+# address.   If a client should get different parameters depending on
+# what subnet it boots on, host declarations for each such network should
+# be given.   Finally, if a domain name is given for a host's fixed address
+# and that domain name evaluates to more than one address, the address
+# corresponding to the network to which the client is attached, if any,
+# will be assigned.
+host confusia {
+  hardware ethernet 02:03:04:05:06:07;
+  fixed-address confusia-1.example.com, confusia-2.example.com;
+  filename "vmunix.confusia";
+  server-name "bootp.example.com";
+}
+
+host confusia {
+  hardware ethernet 02:03:04:05:06:07;
+  fixed-address confusia-3.example.com;
+  filename "vmunix.confusia";
+  server-name "bootp2.example.com";
+}
+
+host confusia {
+  hardware ethernet 02:03:04:05:06:07;
+  filename "vmunix.confusia";
+  server-name "bootp.example.net";
+}
diff -rPU3 net/isc-dhcp2.old/pkg-plist net/isc-dhcp2/pkg-plist
--- net/isc-dhcp2.old/pkg-plist	Sun Nov 25 16:26:21 2001
+++ net/isc-dhcp2/pkg-plist	Sun Nov 25 16:56:08 2001
@@ -1,5 +1,5 @@
 sbin/dhcpd
 sbin/dhcrelay
 etc/rc.d/%%STARTUP_SCRIPT%%
+etc/dhcpd.conf.sample
 @exec touch /var/db/dhcpd.leases
-@exec touch %D/etc/dhclient.conf
